import { Router } from 'express';
import { prisma } from '../db';
import { requireAuth, requireRole } from '../auth/middleware';
import { z } from 'zod';

const router = Router();

const CreatePostSchema = z.object({
  title: z.string().min(1).max(200),
  content: z.string().min(1),
  slug: z.string().regex(/^[a-z0-9-]+$/).max(100),
  tags: z.array(z.string()).optional(),
});

router.get('/', async (req, res) => {
  const { page = '1', limit = '20', search } = req.query as Record<string, string>;
  const skip = (parseInt(page) - 1) * parseInt(limit);
  const where = search
    ? { published: true, OR: [{ title: { contains: search } }, { content: { contains: search } }] }
    : { published: true };
  const [posts, total] = await Promise.all([
    prisma.post.findMany({ where, skip, take: parseInt(limit), include: { author: { select: { id: true, name: true } }, tags: true }, orderBy: { publishedAt: 'desc' } }),
    prisma.post.count({ where }),
  ]);
  res.json({ posts, total, page: parseInt(page), limit: parseInt(limit) });
});

router.post('/', requireAuth, async (req, res) => {
  const body = CreatePostSchema.parse(req.body);
  const post = await prisma.post.create({
    data: { ...body, authorId: (req as any).userId, tags: body.tags ? { connectOrCreate: body.tags.map(t => ({ where: { name: t }, create: { name: t } })) } : undefined },
  });
  res.status(201).json(post);
});

router.put('/:id/publish', requireAuth, requireRole('EDITOR', 'ADMIN'), async (req, res) => {
  const post = await prisma.post.update({
    where: { id: req.params.id },
    data: { published: true, publishedAt: new Date() },
  });
  res.json(post);
});

